const roles = $input.first().json.roles;
const order = ['captain', 'mapmaker', 'quartermaster', 'hunter', 'ships-doctor', 'carpenter', 'council', 'librarian'];
const labels = { 'captain': 'Captain', 'mapmaker': 'MapMaker', 'quartermaster': 'Quartermaster', 'hunter': 'Hunter', 'ships-doctor': "Ship's Doctor", 'carpenter': 'Carpenter', 'council': 'Council', 'librarian': 'Librarian' };
const now = new Date().toISOString().slice(0, 10);
const lines = ['👥 *Crew Levels* — ' + now, '', '```'];
lines.push('Role          | Lv | XP  | Next');
lines.push('--------------|----|-----|-----');
for (const role of order) {
  const r = roles[role];
  if (!r || !r.deployed) { lines.push(labels[role].padEnd(13) + ' | —  | (not deployed)'); continue; }
  const nextThreshold = r.level >= 5 ? '—' : String(r.thresholds[r.level - 1] - r.xp);
  lines.push(labels[role].padEnd(13) + ' | ' + String(r.level).padStart(2) + ' | ' + String(r.xp).padStart(3) + ' | ' + nextThreshold.padStart(4));
}
lines.push('```');
return [{ json: { text: lines.join('\n'), chat_id: $('Telegram Trigger').first().json.message.chat.id } }];
